class Solution {
public:
    int calculate(string s) {
        int num = 0, stack = 0, sign = 1, res = 0;
        for (char c : s) {
            if (isdigit(c)) {
                num = num * 10 + c - '0';
            } else if (c == '+' || c == '-') {
                res += sign * num;
                num = 0;
                sign = (c == '+') ? 1 : -1;
            } else if (c == '*' || c == '/') {
                if (c == '*') {
                    num *= stack;
                } else {
                    num /= stack;
                }
            } else if (c != ' ') {
                stack = num;
                num = 0;
            }
        }
        res += sign * num;
        return res;
    }
};

